    52→async fn run_mcp_scan(installed_dir: &Path) -> anyhow::Result<Value> {
    53→    let mut cmd = if command_available("uvx").await {
    54→        let mut c = tokio::process::Command::new("uvx");
    55→        c.arg("mcp-scan@latest");
    56→        c
    57→    } else {
    58→        tokio::process::Command::new("mcp-scan")
    59→    };
